# Bayesianlibrary(rjags)# Bayesian unpenalized linear model with multivariate meta-analysis or mixing of MCMC samplesBayesian_unpenalized_linear_model <- function(data,                         newX,                         covariate_names,                         outcome = "y",                        treatment = "treatment",                          second_stage # Bayesian MA or mixing of MCMC samples                        ){	Bayesian.LM.obj <- BayesianLM(studies_data = data,					n.covariates = length(covariate_names),					nstudies = length(data),					cov_names = covariate_names,                     outcome = outcome,                    treatment = treatment)	newX.matrix <- as.matrix(newX)	if(second_stage == "Bayesian-MA"){		parameters_to_meta_analyze <- Bayesian.LM.obj[[1]]		to_return <- second_stage(obj_first_stage = parameters_to_meta_analyze)    class(to_return) <- "Bayesian_MVMA"	} else {		to_return <- Bayesian.LM.obj[[2]]    class(to_return) <- "mixing_MCMC_unpenalized"		}	return(to_return)}predict.Bayesian_MVMA <- function(obj.Bayesian_UP, newX){  newX.matrix <- as.matrix(newX)  to_return <- obj.Bayesian_UP["theta_delta", "Estimate"] +       newX.matrix %*% obj.Bayesian_UP[startsWith(rownames(obj.Bayesian_UP), "gamma"), "Estimate"]  return(to_return)}predict.mixing_MCMC_unpenalized <- function(obj.Bayesian_UP, newX){  newX.matrix <- as.matrix(newX)  to_return <- second_stage_ITE(covariates_test_data = newX.matrix)  return(to_return)}# Bayesian LASSO with mixing of MCMC samplesBayesian_LASSO <- function(data, newX, covariate_names, outcome = "y", treatment = "treatment"){	n_covariates <- length(covariate_names)  nstudies <- length(data)  studies_means <- matrix(nrow = nstudies, ncol = n_covariates + 1)  studies_sds <- matrix(nrow = nstudies, ncol = n_covariates + 1)  studies_means[, 1] <- studies_sds[, 1] <- 1:nstudies  total_studies <- do.call(rbind, data)    for(j in seq_along(covariate_names)){    is_dummy <- all(total_studies[[covariate_names[j]]] %in% c(0, 1))    if(is_dummy){      studies_means[, j + 1] <- 0; studies_sds[, j] <- 1    } else {      for(i in 1:nstudies){        studies_means[i, j + 1] <- mean(data[[i]][[covariate_names[[j]]]])        studies_sds[i, j + 1] <- sd(data[[i]][[covariate_names[[j]]]])      }    }  }        std_data <- vector("list", length = nstudies)    for(l in 1:nstudies){      cov_std <- scale(data[[l]][, covariate_names],                        center = studies_means[l, -1],                       scale = studies_sds[l, -1])      std_data[[l]] <- cbind(data[[l]][[response]], data[[l]][[treatment]], cov_std)      colnames(std_data) <-  c("y", "treatment" ,covariate_names)    }        p <- BayesLASSO.I_stage(studies_data = std_data,                             n.covariates = n_covariates,                             nstudies = nstudies)        to_return <- list(posterior_samples = p,                      studies_means = studies_means,                      studies_sds = studies_sds)    return(to_return)} predict.mixing_MCMC_LASSO <- function(BayesianLASSO.train, newX){    cov <- as.matrix(newX)         predictions <- second_stage_LASSO(covariates_test_data = cov,                                       posterior_samples = BayesianLASSO.train$p,                                      s.means = BayesianLASSO.train$studies_means,                                      s.sds = BayesianLASSO.train$studies_sds,                                      nstudies = )     return(predictions)}  